# red_team/risk_register.py
"""Maintain a persistent risk register updated after each exercise."""
import json, pathlib, datetime
from typing import List, Dict

REGISTER_PATH = pathlib.Path("risk_register.json")

def load_register() -> List[Dict]:
    if REGISTER_PATH.exists():
        return json.loads(REGISTER_PATH.read_text())
    return []

def upsert_finding(register: List[Dict], finding: Dict) -> List[Dict]:
    """Add new finding or update existing by ID."""
    existing_ids = {r["id"] for r in register}
    if finding["id"] in existing_ids:
        register = [finding if r["id"] == finding["id"] else r for r in register]
    else:
        register.append(finding)
    return register

def close_finding(register: List[Dict], finding_id: str, resolution: str) -> List[Dict]:
    for r in register:
        if r["id"] == finding_id:
            r["status"] = "closed"
            r["resolution"] = resolution
            r["closed_date"] = datetime.date.today().isoformat()
    return register

def save_register(register: List[Dict]):
    REGISTER_PATH.write_text(json.dumps(register, indent=2, sort_keys=True))

def open_findings_by_severity(register: List[Dict]) -> Dict[str, List[Dict]]:
    open_r = [r for r in register if r.get("status") != "closed"]
    result: Dict[str, List[Dict]] = {"critical": [], "high": [], "medium": [], "low": []}
    for r in open_r:
        sev = r.get("severity", "low")
        if sev in result:
            result[sev].append(r)
    return result
